const items = $input.all();
let allConversations = [];
for (const item of items) {
  const data = item.json.data || [];
  allConversations = allConversations.concat(data);
}
// Deduplicate by conversation id
const seen = new Set();
const unique = allConversations.filter(c => {
  if (seen.has(c.id)) return false;
  seen.add(c.id);
  return true;
});
return unique.map(c => ({ json: c }));

try {
  const messages = $('Get Messages').item.json.data || [];
  const conversationId = $('Split Conversations').item.json.id;
  const participants = $('Split Conversations').item.json.participants?.data || [];
  const igUserId = $('Configure Global Settings').first().json.igUserId;
  const accessToken = $('Configure Global Settings').first().json.accessToken;

  // Get replied history
  const historyNode = $('Read DM History').item;
  let history = [];
  if (historyNode.binary) {
    const binaryKey = Object.keys(historyNode.binary)[0];
    const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
    history = JSON.parse(buffer.toString('utf8')).replied_message_ids || [];
  } else {
    history = historyNode.json.replied_message_ids || [];
  }

  // Get products
  const productsNode = $('Read products.json').item;
  let products = [];
  if (productsNode.binary) {
    const binaryKey = Object.keys(productsNode.binary)[0];
    const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
    products = JSON.parse(buffer.toString('utf8')).products || [];
  } else {
    products = productsNode.json.products || [];
  }

  // Find the sender (not our IG account)
  const sender = participants.find(p => p.id !== igUserId);
  if (!sender) return [{ json: { decision: 'skip' } }];

  // Filter messages: not replied, from sender (not us), contains a keyword
  const toProcess = [];
  for (const msg of messages) {
    if (history.includes(msg.id)) continue;
    if (msg.from?.id === igUserId) continue;
    const text = (msg.message || '').toLowerCase();

    for (const product of products) {
      const keyword = (product.keyword || 'link').toLowerCase();
      if (text.includes(keyword)) {
        toProcess.push({
          json: {
            decision: 'process',
            messageId: msg.id,
            senderId: sender.id,
            senderName: sender.name || 'there',
            keyword: product.keyword,
            productTitle: product.title,
            affiliateUrl: product.affiliateUrl,
            replyMessage: `Hey! You asked for the link to ${product.title}. Here it is: ${product.affiliateUrl} 🎉`,
            accessToken,
            igUserId
          }
        });
        break;
      }
    }
  }

  if (toProcess.length === 0) {
    return [{ json: { decision: 'skip' } }];
  }

  return toProcess;
} catch(e) {
  return [{ json: { decision: 'skip', error: e.message } }];
}

const messageId = $('Split DMs').item.json.messageId;
const historyNode = $('Read Fresh DM History').item;
let historyObj = { replied_message_ids: [] };

if (historyNode.binary) {
  const binaryKey = Object.keys(historyNode.binary)[0];
  const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
  historyObj = JSON.parse(buffer.toString('utf8'));
} else {
  historyObj = historyNode.json;
}

if (!historyObj.replied_message_ids.includes(messageId)) {
  historyObj.replied_message_ids.push(messageId);
}

return historyObj;
